    func generatePrivateKey() -> Data {
        return CryptoKit.SECKey.generate().rawRepresentation!
    }
    
    func signTransaction(privateKey: Data, transactionData: String) -> Data? {
        guard let key = try? CryptoKit.SECKey(rawRepresentation: privateKey),
              let data = transactionData.data(using: .utf8) else {
